import { cn } from '@/utils/cn';
import { trackElement, untrackElement } from '@/utils/element-tracker';
import { ZIndex, ZIndexType } from '@components/z-index';
import { cva, VariantProps } from 'class-variance-authority';
import {
  createContext,
  createEffect,
  createSignal,
  createUniqueId,
  mergeProps,
  onCleanup,
  ParentComponent,
  useContext,
} from 'solid-js';
import { dropdownStore } from './dropdown.store';
import { DropdownProps } from './dropdown.types';

/** Context truyền `closeAll` từ dropdown root xuống tất cả dropdown con */
const CloseAllContext = createContext(false);

const variants = cva('', {
  variants: {
    position: {
      top: 'dropdown-top',
      bottom: 'dropdown-bottom',
      left: 'dropdown-left',
      right: 'dropdown-right',
    },
    align: {
      start: 'dropdown-start',
      center: 'dropdown-center',
      end: 'dropdown-end',
    },
  },
});
export type DropdownVariantsProps = VariantProps<typeof variants>;

type TriggerRect = {
  top: number;
  left: number;
  width: number;
  height: number;
};

export const Dropdown: ParentComponent<DropdownProps> = props => {
  const p = mergeProps(
    {
      position: 'bottom' as const,
      align: 'start' as const,
      blockScroll: true,
      closeAll: false,
    },
    props,
  );

  // Kế thừa closeAll từ dropdown cha nếu có
  const parentCloseAll = useContext(CloseAllContext);
  const shouldCloseAll = () => p.closeAll || parentCloseAll;

  const id = createUniqueId();
  const isControlled = () => p.open !== undefined;

  let triggerRef!: HTMLDivElement;
  const [rect, setRect] = createSignal<TriggerRect | null>(null);

  const captureRect = () => {
    const r = triggerRef.getBoundingClientRect();
    setRect({ top: r.top, left: r.left, width: r.width, height: r.height });
  };

  const isOpen = () => {
    if (isControlled()) return !!p.open;
    return dropdownStore.isOpen(id);
  };

  createEffect(function trackTrigger() {
    if (!isOpen()) {
      untrackElement(triggerRef);
      return;
    }
    trackElement(triggerRef, r => setRect(r));
    onCleanup(function untrackTrigger() {
      untrackElement(triggerRef);
    });
  });

  createEffect(function handleControlledOpen() {
    if (!isControlled()) return;
    if (p.open) {
      captureRect();
      dropdownStore.open(id);
    } else {
      dropdownStore.close(id);
    }
  });

  onCleanup(function closeDropdownOnUnmount() {
    dropdownStore.close(id);
    untrackElement(triggerRef);
  });

  const toggle = () => {
    if (dropdownStore.isOpen(id)) {
      dropdownStore.close(id);
    } else {
      captureRect();
      dropdownStore.open(id);
    }
  };

  const close = () => (shouldCloseAll() ? dropdownStore.closeAll() : dropdownStore.close(id));

  const anchorStyle = () => {
    const r = rect();
    if (!r) return {};
    return {
      '--nd-t': `${r.top}px`,
      '--nd-l': `${r.left}px`,
      '--nd-w': `${r.width}px`,
      '--nd-h': `${r.height}px`,
    } as Record<string, string>;
  };
  return (
    <>
      <div
        ref={el => {
          triggerRef = el;
          const ref = p.ref;
          if (typeof ref === 'function') ref(el);
        }}
        class={cn('dp01', p.class?.trigger)}
        onClick={isControlled() ? undefined : toggle}
      >
        {p.triggerElement as Element}
      </div>

      <ZIndex
        open={isOpen()}
        type={ZIndexType.DROPDOWN}
        blockScroll={p.blockScroll}
        class={cn('inset-0', parentCloseAll && 'pointer-events-none')}
        customValue={p.zIndex}
      >
        {!parentCloseAll && <div class="dp02" onClick={close} />}

        <div
          class={cn('dp03', p.class?.anchor)}
          data-pos={p.position}
          data-align={p.align}
          style={anchorStyle()}
        >
          <div class={cn('dp04', p.class?.content)}>
            <CloseAllContext.Provider value={shouldCloseAll()}>
              {p.children}
            </CloseAllContext.Provider>
          </div>
        </div>
      </ZIndex>
    </>
  );
};
